#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>
#include <string.h>

typedef struct latLong
{
    float lat;
    float lng;
} LatLong;

typedef struct record
{
    char recString[49];
    float distance;
} Record;

typedef struct recordList {
    Record *records;
    int size;
    int capacity;
} recordList;

typedef struct latLongList {
    LatLong *locations;
    int size;
    int capacity;
} latLongList;

void recordList_init(recordList *list) {
    list->size = 0;
    list->capacity = 16;
    list->records = (Record *)malloc(list->capacity * sizeof(Record));
    if (!list->records) {
        fprintf(stderr, "Failed to allocate records list\n");
        exit(1);
    }
}

void recordList_push_back(recordList *list, Record *rec) {
    if (list->size >= list->capacity) {
        list->capacity *= 2;
        list->records = (Record *)realloc(list->records, list->capacity * sizeof(Record));
        if (!list->records) {
            fprintf(stderr, "Failed to reallocate records list\n");
            exit(1);
        }
    }
    list->records[list->size++] = *rec;
}

void recordList_free(recordList *list) {
    free(list->records);
    list->records = NULL;
    list->size = 0;
    list->capacity = 0;
}

void latLongList_init(latLongList *list) {
    list->size = 0;
    list->capacity = 16;
    list->locations = (LatLong *)malloc(list->capacity * sizeof(LatLong));
    if (!list->locations) {
        fprintf(stderr, "Failed to allocate locations list\n");
        exit(1);
    }
}

void latLongList_push_back(latLongList *list, LatLong *loc) {
    if (list->size >= list->capacity) {
        list->capacity *= 2;
        list->locations = (LatLong *)realloc(list->locations, list->capacity * sizeof(LatLong));
        if (!list->locations) {
            fprintf(stderr, "Failed to reallocate locations list\n");
            exit(1);
        }
    }
    list->locations[list->size++] = *loc;
}

void latLongList_free(latLongList *list) {
    free(list->locations);
    list->locations = NULL;
    list->size = 0;
    list->capacity = 0;
}

void NearestNeighbor(LatLong *d_locations,
                     float *d_distances,
                     const int numRecords,
                     const float lat,
                     const float lng) {
#pragma omp parallel for
    for (int globalId = 0; globalId < numRecords; globalId++) {
        LatLong *latLong = d_locations + globalId;
        float *dist = d_distances + globalId;
        *dist = (float)sqrt((lat - latLong->lat) * (lat - latLong->lat) + (lng - latLong->lng) * (lng - latLong->lng));
    }
}

float *OpenClFindNearestNeighbors(
    int numRecords,
    LatLong *locations, float lat, float lng) {

    float *distances = (float *)malloc(sizeof(float) * numRecords);
    if (!distances) {
        fprintf(stderr, "Failed to allocate distances array\n");
        exit(1);
    }

    NearestNeighbor(locations, distances, numRecords, lat, lng);

    return distances;
}

int loadData(char *filename, recordList *records, latLongList *locations) {
    FILE *flist, *fp;
    int i = 0;
    char dbname[64], db_fullname[128];
    int recNum = 0;

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "Error opening file list: %s\n", filename);
        exit(1);
    }
    while (fscanf(flist, "%63s\n", dbname) == 1) {
        sprintf(db_fullname, "%s/%s", ".", dbname);
        fp = fopen(db_fullname, "r");
        if (!fp) {
            printf("error opening a db (%s)\n", db_fullname);
            exit(1);
        }

        while (1) {
            Record record;
            LatLong latLong;
            if (!fgets(record.recString, 49, fp)) break;
            if (feof(fp)) break;
            fgetc(fp); // consume newline or separator

            char substr[6];

            for (i = 0; i < 5; i++) substr[i] = *(record.recString + i + 28);
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for (i = 0; i < 5; i++) substr[i] = *(record.recString + i + 33);
            substr[5] = '\0';
            latLong.lng = atof(substr);

            recordList_push_back(records, &record);
            latLongList_push_back(locations, &latLong);
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);
    return recNum;
}

void findLowest(recordList *records, float *distances, int numRecords, int topN) {
    int i, j;
    float val;
    int minLoc;
    Record tempRec;
    float tempDist;

    for (i = 0; i < topN; i++) {
        minLoc = i;
        for (j = i; j < numRecords; j++) {
            val = distances[j];
            if (val < distances[minLoc]) minLoc = j;
        }

        tempRec = records->records[i];
        records->records[i] = records->records[minLoc];
        records->records[minLoc] = tempRec;

        tempDist = distances[i];
        distances[i] = distances[minLoc];
        distances[minLoc] = tempDist;

        records->records[i].distance = distances[i];
    }
}

int parseCommandline(int argc, char *argv[], char *filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
    int i;
    if (argc < 2) return 1;
    strncpy(filename, argv[1], 100);
    char flag;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
            case 'r':
                i++;
                *r = atoi(argv[i]);
                break;
            case 'l':
                if (argv[i][2] == 'a') {
                    *lat = atof(argv[i + 1]);
                } else {
                    *lng = atof(argv[i + 1]);
                }
                i++;
                break;
            case 'h':
                return 1;
            case 'q':
                *q = 1;
                break;
            case 't':
                *t = 1;
                break;
            case 'p':
                i++;
                *p = atoi(argv[i]);
                break;
            case 'd':
                i++;
                *d = atoi(argv[i]);
                break;
            case 'f':
                i++;
                // data_folder is not used here, so ignore
                break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

void printUsage() {
    printf("Nearest Neighbor Usage\n");
    printf("\n");
    printf("nearestNeighbor [filename] -r [int] -lat [float] -lng [float] [-hqt] [-p [int] -d [int]]\n");
    printf("\n");
    printf("example:\n");
    printf("$ ./nearestNeighbor filelist.txt -r 5 -lat 30 -lng 90\n");
    printf("\n");
    printf("filename     the filename that lists the data input files\n");
    printf("-r [int]     the number of records to return (default: 10)\n");
    printf("-lat [float] the latitude for nearest neighbors (default: 0)\n");
    printf("-lng [float] the longitude for nearest neighbors (default: 0)\n");
    printf("\n");
    printf("-h, --help   Display the help file\n");
    printf("-q           Quiet mode. Suppress all text output.\n");
    printf("-t           Print timing information.\n");
    printf("\n");
    printf("-p [int]     Choose the platform (must choose both platform and device)\n");
    printf("-d [int]     Choose the device (must choose both platform and device)\n");
    printf("\n");
    printf("\n");
    printf("Notes: 1. The filename is required as the first parameter.\n");
    printf("       2. If you declare either the device or the platform,\n");
    printf("          you must declare both.\n\n");
}

int main(int argc, char *argv[]) {
    recordList records;
    latLongList locations;
    float *recordDistances;

    int i;

    char filename[100];
    int resultsCount = 10, quiet = 0, timing = 0, platform = -1, device = -1;
    float lat = 0.0, lng = 0.0;

    if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                         &quiet, &timing, &platform, &device)) {
        printUsage();
        return 0;
    }

    recordList_init(&records);
    latLongList_init(&locations);

    int numRecords = loadData(filename, &records, &locations);

    if (!quiet) {
        printf("Number of records: %d\n", numRecords);
        printf("Finding the %d closest neighbors.\n", resultsCount);
    }

    if (resultsCount > numRecords)
        resultsCount = numRecords;

    recordDistances = OpenClFindNearestNeighbors(numRecords, locations.locations, lat, lng);

    findLowest(&records, recordDistances, numRecords, resultsCount);

    if (!quiet)
        for (i = 0; i < resultsCount; i++) {
            printf("%s --> Distance=%f\n", records.records[i].recString, records.records[i].distance);
        }
    free(recordDistances);
    recordList_free(&records);
    latLongList_free(&locations);
    return 0;
}
